// Verify required env vars are present. Fails visibly if absent.
const required = ['DRIVE_FOLDER_ID', 'CLIENT_EMAIL', 'DISCORD_BOT_TOKEN', 'OLLAMA_BASE_URL'];
const missing = required.filter(k => !process.env[k] || process.env[k].trim() === '');
if (missing.length > 0) {
  throw new Error('FATAL: Missing env vars for report draft: ' + missing.join(', '));
}
return [{ json: { trigger_source: $json.trigger_source } }];

// Load roster.yml and extract Team Lead channel and Discord ID.
const fs = require('fs');
const yaml = require('js-yaml');
const path = process.env.ROSTER_CONFIG_PATH || '/data/roster.yml';
let roster;
try {
  roster = yaml.load(fs.readFileSync(path, 'utf8'));
} catch (e) {
  throw new Error('Report draft: cannot load roster.yml: ' + e.message);
}
return [{
  json: {
    trigger_source: $json.trigger_source,
    team_lead_channel_id: roster.team_lead_channel_id,
    team_lead_discord_id: roster.team_lead.discord_id,
    roster_names: roster.team.map(m => m.name).concat([roster.team_lead.name])
  }
}];

// Compute date range for report period
const now = new Date();
const oneWeekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
return [{
  json: {
    ...$json,
    one_week_ago_iso: oneWeekAgo.toISOString(),
    today_iso: now.toISOString().split('T')[0]
  }
}];

// Aggregate feature-level hints from GitHub and Jira.
// CRITICAL: No author name, no commit author, no assignee, no individual attribution (SC-17).
// Inputs arrive via the Merge node: items[0]=PR result, items[1]=commits result, items[2]=Jira result
const allItems = $input.all();
const prResult = allItems[0] ? allItems[0].json : null;
const commitResult = allItems[1] ? allItems[1].json : null;
const jiraResult = allItems[2] ? allItems[2].json : null;
const sourcesUnavailable = [];

// Extract PR titles and labels only — no author fields
let openPrs = [];
if (Array.isArray(prResult)) {
  openPrs = prResult.slice(0, 10).map(pr => pr.title).filter(Boolean);
} else {
  sourcesUnavailable.push('GitHub PRs');
}

// Extract commit messages only — no author attribution
let commitThemes = [];
if (Array.isArray(commitResult)) {
  commitThemes = commitResult.slice(0, 10).map(c => c.commit && c.commit.message ? c.commit.message.split('\n')[0] : null).filter(Boolean);
} else {
  sourcesUnavailable.push('GitHub commits');
}

// Extract Jira issue summaries and statuses only — no assignee
let jiraFeatures = [];
if (jiraResult && Array.isArray(jiraResult.issues)) {
  jiraFeatures = jiraResult.issues.slice(0, 15).map(issue => ({
    summary: issue.fields && issue.fields.summary ? issue.fields.summary : '',
    status: issue.fields && issue.fields.status ? issue.fields.status.name : ''
    // Explicitly NOT extracting: assignee, reporter, author
  })).filter(f => f.summary);
} else {
  sourcesUnavailable.push('Jira');
}

return [{
  json: {
    ...$node['Load Roster'].json,
    one_week_ago_iso: $node['Compute Date Range'].json.one_week_ago_iso || new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString(),
    today_iso: $node['Compute Date Range'].json.today_iso || new Date().toISOString().split('T')[0],
    trigger_source: $node['Normalise Trigger Source'].json.trigger_source,
    hints: {
      open_prs: openPrs,
      recent_commit_themes: commitThemes,
      jira_features: jiraFeatures,
      sources_unavailable: sourcesUnavailable
    }
  }
}];

// Assemble Ollama LLM request body.
// System prompt is verbatim from the planner — do not alter.
const memRow = $input.first().json;
const hintsData = $node['Aggregate Hints (No Individual Attribution)'].json;
const hints = hintsData.hints;
const projectPicture = memRow && memRow.value_json ? (typeof memRow.value_json === 'string' ? memRow.value_json : JSON.stringify(memRow.value_json)) : null;

const systemPrompt = `You are a project coordination assistant. Your task is to draft a concise, honest, project-level progress report for the client.

MANDATORY RULES — violating any of these is a critical error:
1. The report must be fully project-level. It must not name, attribute to, or identify any individual team member in any way — not by name, role, initials, or any detail that could identify one person.
2. Do not include commit counts, hours logged, pull request counts, or any numeric metric attributable to a person or implying individual productivity.
3. Do not speculate about whether work is "behind" or "at risk" based solely on low activity metrics. Only describe what is demonstrably progressing or demonstrably blocked at the feature level.
4. If there is little new to report since the last report, say so honestly. Do not fabricate progress.
5. Use plain English suitable for a non-technical client. Keep the report under 400 words.
6. Structure the report as: (a) What progressed this week, (b) What is next, (c) Any known blockers at the feature level.

You will be given feature-level signals from version control and issue tracking. These are supplementary hints only — treat them as directional, not as ground truth.`;

const userMessage = `Draft a client progress report based on these signals.

GitHub signals: ${JSON.stringify(hints.open_prs)}
Jira signals: ${JSON.stringify(hints.jira_features)}
Recent themes from commit messages: ${JSON.stringify(hints.recent_commit_themes)}
Project memory (may be empty): ${projectPicture || 'No stored project context yet.'}
Sources unavailable: ${hints.sources_unavailable.join(', ') || 'None'}

Remember: fully project-level only. No individual names, no productivity metrics.`;

const requestBody = {
  model: 'llama3',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ],
  temperature: 0.3,
  stream: false
};

return [{ json: {
  llm_request: requestBody,
  team_lead_channel_id: hintsData.team_lead_channel_id,
  team_lead_discord_id: hintsData.team_lead_discord_id,
  roster_names: hintsData.roster_names,
  trigger_source: hintsData.trigger_source,
  today_iso: hintsData.today_iso
}}];

// Extract LLM response. Handle Ollama failure gracefully.
const result = $input.first().json;
const teamLeadChannelId = $node['Assemble LLM Prompt'].json.team_lead_channel_id;

// Check for HTTP error (continueOnFail passes the error in $json.error)
if (result.error || !result.choices || !result.choices[0]) {
  return [{ json: {
    llm_failed: true,
    team_lead_channel_id: teamLeadChannelId,
    error_message: result.error ? result.error.message : 'No response from LLM'
  }}];
}

let draftText = result.choices[0].message.content || '';
// Strip markdown code fences
draftText = draftText.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '').trim();

return [{ json: {
  llm_failed: false,
  draft_text: draftText,
  team_lead_channel_id: $node['Assemble LLM Prompt'].json.team_lead_channel_id,
  team_lead_discord_id: $node['Assemble LLM Prompt'].json.team_lead_discord_id,
  roster_names: $node['Assemble LLM Prompt'].json.roster_names,
  trigger_source: $node['Assemble LLM Prompt'].json.trigger_source,
  today_iso: $node['Assemble LLM Prompt'].json.today_iso
}}];

// Privacy Validation (F-08 enforcement — safety net).
// Scans draft_text for roster member names as whole words.
// The LLM system prompt is the primary control; this is the safety net.
const draftText = $json.draft_text || '';
const rosterNames = $json.roster_names || [];
let validated = draftText;
let warnings = [];

for (const name of rosterNames) {
  if (!name) continue;
  // Match full name and also each individual word in the name
  const escapedName = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(`\\b${escapedName}\\b`, 'gi');
  if (regex.test(validated)) {
    validated = validated.replace(regex, '[REMOVED — individual attribution]');
    warnings.push(`Name '${name}' detected and removed.`);
  }
}

let finalText = validated;
if (warnings.length > 0) {
  finalText += `\n\n[Warning: the agent detected and removed individual attribution. Please review before approving. Removed: ${warnings.join('; ')}]`;
}

return [{ json: {
  draft_text: finalText,
  team_lead_channel_id: $json.team_lead_channel_id,
  team_lead_discord_id: $json.team_lead_discord_id,
  trigger_source: $json.trigger_source,
  today_iso: $json.today_iso,
  privacy_warnings: warnings
}}];
